  1→import React, {useMemo, useState} from 'react';
  2→import {FlatList, ScrollView, StyleSheet, Text, View, useWindowDimensions} from 'react-native';
  3→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
  4→import {NativeStackScreenProps} from '@react-navigation/native-stack';
  5→import {SafeAreaView} from 'react-native-safe-area-context';
  6→import {PostCard} from '../../components/PostCard/PostCard';
  7→import {CanvasPreview} from '../../components/CanvasPreview/CanvasPreview';
  8→import {PostCardSkeleton} from '../../components/SkeletonLoader';
  9→import {CommentModal} from '../../components/Comments';
 10→import {RepostModal} from '../../components/RepostModal';
 11→import {Chip} from '../../components/Chip';
 12→import {EmptyState} from '../../components/EmptyState';
 13→import {useAuth} from '../../features/auth/AuthProvider';
 14→import {useTheme} from '../../theme/ThemeProvider';
 15→import {fonts} from '../../theme/typography';
 16→import {spacing} from '../../theme/spacing';
 17→import {
 18→  mobileApi,
 19→  type CursorPage,
 20→  type JournalItem,
 21→} from '../../lib/api/mobileApi';
 22→import {socialApi} from '../../lib/api/socialApi';
 23→import {queryClient} from '../../lib/queryClient';
 24→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 25→import {
 26→  extractPlainText,
 27→  resolveCount,
 28→  getNextCursor,
 29→  getCanvasPlainText,
 30→} from '../../lib/utils/journalHelpers';
 31→import type {RootStackParamList} from '../../navigation/types';
 32→
 33→type Props = NativeStackScreenProps<RootStackParamList, 'Canvas'>;
 34→
 35→const PAGE_SIZE = 10;
 36→
 37→const SORT_OPTIONS = [
 38→  {key: 'hottest', label: 'Hottest'},
 39→  {key: 'newest', label: 'Newest'},
 40→] as const;
 41→
 42→type SortKey = (typeof SORT_OPTIONS)[number]['key'];
 43→
 44→export function CanvasScreen({navigation}: Props) {
 45→  const {user, session} = useAuth();
 46→  const {colors} = useTheme();
 47→  const {width: windowWidth} = useWindowDimensions();
 48→  const cardWidth = windowWidth - spacing.lg * 2;
 49→  const token = session?.access_token ?? '';
 50→  const [refreshing, setRefreshing] = useState(false);
 51→  const [sort, setSort] = useState<SortKey>('hottest');
 52→  const [commentModal, setCommentModal] = useState<{
 53→    postId: string;
 54→    receiverId?: string;
 55→    commentCount: number;
 56→  } | null>(null);
 57→  const [repostModal, setRepostModal] = useState<{
 58→    journalId: string;
 59→    title?: string;
 60→    authorName?: string;
 61→    authorAvatar?: string;
 62→  } | null>(null);
 63→
 64→  const galleryQuery = useInfiniteQuery({
 65→    queryKey: ['canvas-gallery', user?.id, sort],
 66→    queryFn: ({pageParam}) =>
 67→      mobileApi.getCanvasGallery(user?.id, PAGE_SIZE, sort, pageParam ?? null),
 68→    initialPageParam: null as string | null,
 69→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 70→  });
 71→
 72→  const reactionMutation = useMutation({
 73→    mutationFn: async ({
 74→      journalId,
 75→      receiverId,
 76→      reactionType,
 77→    }: {
 78→      journalId: string;
 79→      receiverId: string;
 80→      reactionType: string;
 81→    }) => {
 82→      if (!token) throw new Error('Please log in to react.');
 83→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 84→    },
 85→    onMutate: async ({journalId, reactionType}) => {
 86→      const qk = ['canvas-gallery', user?.id, sort];
 87→      await queryClient.cancelQueries({queryKey: qk});
 88→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(qk);
 89→      if (prev) {
 90→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(qk, old => {
 91→          if (!old) return old;
 92→          return {
 93→            ...old,
 94→            pages: old.pages.map(page => ({
 95→              ...page,
 96→              data: page.data.map(item => {
 97→                if (item.id !== journalId) return item;
 98→                const removing = item.user_reaction === reactionType;
 99→                const currentCount =
100→                  (item.reaction_count?.[0]?.count ??
101→                    item.like_count?.[0]?.count ??
102→                    item.likes_count ??
103→                    0) as number;
104→                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
105→                return {
106→                  ...item,
107→                  user_reaction: removing ? null : reactionType,
108→                  has_liked: removing ? false : true,
109→                  like_count: [{count: Math.max(0, currentCount + delta)}],
110→                };
111→              }),
112→            })),
113→          };
114→        });
115→      }
116→      return {prev};
117→    },
118→    onError: (_err, _vars, context) => {
119→      if (context?.prev) {
120→        queryClient.setQueryData(
121→          ['canvas-gallery', user?.id, sort],
122→          context.prev,
123→        );
124→      }
125→    },
126→    onSettled: () => {
127→      queryClient.invalidateQueries({queryKey: ['canvas-gallery']});
128→    },
129→  });
130→
131→  const bookmarkMutation = useBookmarkMutation(token, [
132→    'canvas-gallery',
133→    user?.id,
134→    sort,
135→  ]);
136→
137→  const handleReact = (
138→    journalId: string,
139→    receiverId: string,
140→    reactionType: string,
141→  ) => {
142→    if (!token) return;
143→    reactionMutation.mutate({journalId, receiverId, reactionType});
144→  };
145→
146→  const handleComment = (
147→    journalId: string,
148→    receiverId?: string,
149→    commentCount?: number,
150→  ) => {
151→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
152→  };
153→
154→  const handleBookmark = (journalId: string) => {
155→    bookmarkMutation.mutate(journalId);
156→  };
157→
158→  const handleRepost = (
159→    journalId: string,
160→    title?: string,
161→    authorName?: string,
162→    authorAvatar?: string,
163→  ) => {
164→    setRepostModal({journalId, title, authorName, authorAvatar});
165→  };
166→
167→  const posts = useMemo(
168→    () => galleryQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
169→    [galleryQuery.data?.pages],
170→  );
171→
172→  const onRefresh = async () => {
173→    setRefreshing(true);
174→    try {
175→      await galleryQuery.refetch();
176→    } finally {
177→      setRefreshing(false);
178→    }
179→  };
180→
181→  return (
182→    <SafeAreaView
183→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
184→      edges={['top']}>
185→      {/* Header */}
186→      <View style={[styles.header, {borderBottomColor: colors.borderCard}]}>
187→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
188→          Canvas
189→        </Text>
190→      </View>
191→
192→      {/* Sort chips */}
193→      <View style={styles.chipRow}>
194→        <ScrollView
195→          horizontal
196→          showsHorizontalScrollIndicator={false}
197→          contentContainerStyle={styles.chipScroll}>
198→          {SORT_OPTIONS.map(option => (
199→            <Chip
200→              key={option.key}
201→              label={option.label}
202→              active={sort === option.key}
203→              onPress={() => setSort(option.key)}
204→            />
205→          ))}
206→        </ScrollView>
207→      </View>
208→
209→      {/* Gallery */}
210→      <FlatList
211→        data={posts}
212→        onRefresh={onRefresh}
213→        refreshing={refreshing}
214→        onEndReachedThreshold={0.25}
215→        onEndReached={() => {
216→          if (galleryQuery.hasNextPage && !galleryQuery.isFetchingNextPage) {
217→            galleryQuery.fetchNextPage();
218→          }
219→        }}
220→        contentContainerStyle={styles.listContent}
221→        showsVerticalScrollIndicator={false}
222→        ListEmptyComponent={
223→          galleryQuery.isLoading ? (
224→            <View style={styles.skeletonList}>
225→              <PostCardSkeleton />
226→              <PostCardSkeleton />
227→              <PostCardSkeleton />
228→            </View>
229→          ) : (
230→            <EmptyState
231→              title="No canvas posts yet"
232→              subtitle="Pull to refresh or create your first canvas post."
233→            />
234→          )
235→        }
236→        ListFooterComponent={
237→          galleryQuery.isFetchingNextPage ? (
238→            <View style={styles.loadingMore}>
239→              <PostCardSkeleton />
240→            </View>
241→          ) : null
242→        }
243→        keyExtractor={item => item.id}
244→        renderItem={({item}) => {
245→          const canvasText = getCanvasPlainText(item.canvas_doc);
246→          const preview = (canvasText || extractPlainText(item.content)).slice(0, 180);
247→          const likeCount = resolveCount(item.like_count, item.likes_count);
248→          const commentCount = resolveCount(
249→            item.comment_count,
250→            item.comments_count,
251→          );
252→          const bookmarkCount = resolveCount(item.bookmark_count);
253→          const bannerNode = (
254→            <CanvasPreview canvasDoc={item.canvas_doc ?? null} width={cardWidth} />
255→          );
256→
257→          const receiverId = item.user_id ?? item.users?.id ?? '';
258→
259→          const handleAuthorPress = () => {
260→            const authorId = item.users?.id ?? item.user_id;
261→            if (!authorId) return;
262→            if (authorId === user?.id) {
263→              navigation.navigate('Main' as any, {screen: 'Profile'});
264→            } else {
265→              navigation.navigate('VisitProfile', {
266→                userId: authorId,
267→                username: item.users?.username ?? undefined,
268→              });
269→            }
270→          };
271→
272→          const isRepost = !!item.is_repost;
273→          const repostSource = isRepost ? item.repost_source : null;
274→          const repostSourcePreview = repostSource?.content
275→            ? extractPlainText(repostSource.content).slice(0, 180)
276→            : '';
277→
278→          return (
279→            <PostCard
280→              title={item.title || 'Untitled Post'}
281→              bodyPreview={preview || 'No preview text available.'}
282→              authorName={item.users?.name || 'Unknown author'}
283→              authorAvatar={item.users?.image_url}
284→              authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
285→              bannerContent={bannerNode}
286→              postType={item.post_type ?? 'canvas'}
287→              likeCount={likeCount}
288→              commentCount={commentCount}
289→              bookmarkCount={bookmarkCount}
290→              userReaction={item.user_reaction}
291→              isBookmarked={!!item.has_bookmarked}
292→              onReact={type => handleReact(item.id, receiverId, type)}
293→              onComment={() => handleComment(item.id, receiverId, commentCount)}
294→              onBookmark={() => handleBookmark(item.id)}
295→              onRepost={() =>
296→                handleRepost(
297→                  item.id,
298→                  item.title ?? undefined,
299→                  item.users?.name ?? undefined,
300→                  item.users?.image_url ?? undefined,
301→                )
302→              }
303→              onPress={() =>
304→                navigation.navigate('PostDetail', {journalId: item.id})
305→              }
306→              onAuthorPress={handleAuthorPress}
307→              isRepost={isRepost}
308→              repostCaption={item.repost_caption}
309→              repostSourceTitle={repostSource?.title}
310→              repostSourcePreview={repostSourcePreview}
311→              repostSourceAuthorName={repostSource?.users?.name}
312→              repostSourceAuthorAvatar={repostSource?.users?.image_url}
313→              onEmbeddedPress={
314→                repostSource
315→                  ? () =>
316→                      navigation.navigate('PostDetail', {
317→                        journalId: repostSource.id,
318→                      })
319→                  : undefined
320→              }
321→            />
322→          );
323→        }}
324→        ItemSeparatorComponent={() => <View style={styles.separator} />}
325→      />
326→
327→      {commentModal && (
328→        <CommentModal
329→          visible
330→          postId={commentModal.postId}
331→          receiverId={commentModal.receiverId}
332→          commentCount={commentModal.commentCount}
333→          onClose={() => setCommentModal(null)}
334→        />
335→      )}
336→
337→      {repostModal && (
338→        <RepostModal
339→          visible
340→          sourceJournalId={repostModal.journalId}
341→          title={repostModal.title}
342→          authorName={repostModal.authorName}
343→          authorAvatar={repostModal.authorAvatar}
344→          onClose={() => setRepostModal(null)}
345→        />
346→      )}
347→    </SafeAreaView>
348→  );
349→}
350→
351→const styles = StyleSheet.create({
352→  safe: {
353→    flex: 1,
354→  },
355→  header: {
356→    paddingHorizontal: spacing.lg,
357→    paddingVertical: spacing.md,
358→    borderBottomWidth: StyleSheet.hairlineWidth,
359→  },
360→  brandText: {
361→    fontFamily: fonts.brand.semiBold,
362→    fontSize: 24,
363→    letterSpacing: 1,
364→  },
365→  chipRow: {
366→    paddingVertical: spacing.sm,
367→  },
368→  chipScroll: {
369→    paddingHorizontal: spacing.lg,
370→    gap: spacing.sm,
371→  },
372→  listContent: {
373→    paddingHorizontal: spacing.lg,
374→    paddingBottom: 100,
375→  },
376→  separator: {
377→    height: spacing.md,
378→  },
379→  skeletonList: {
380→    gap: spacing.md,
381→    paddingTop: spacing.md,
382→  },
383→  loadingMore: {
384→    paddingTop: spacing.md,
385→  },
386→});
