  1→import React, {useMemo} from 'react';
  2→import {Image, StyleSheet, Text, View} from 'react-native';
  3→import Svg, {Polyline} from 'react-native-svg';
  4→import {fonts} from '../../theme/typography';
  5→import {parseCanvasDoc} from '../../lib/utils/journalHelpers';
  6→import type {CanvasDoc, CanvasDoodle, CanvasImage, CanvasSnippet} from '../../lib/api/mobileApi';
  7→
  8→interface CanvasPreviewProps {
  9→  canvasDoc: CanvasDoc | string | null;
 10→  width: number;
 11→}
 12→
 13→const STAGE_WIDTH = 560;
 14→
 15→const ASPECT_RATIOS: Record<string, number> = {
 16→  '1:1': 1,
 17→  '4:5': 4 / 5,
 18→};
 19→
 20→const FONT_MAP: Record<string, string> = {
 21→  handwritten: fonts.brand.semiBoldItalic,
 22→  serif: fonts.serif.regular,
 23→  mono: fonts.serif.regular,
 24→  bold: fonts.ui.bold,
 25→  serifDisplay: fonts.brand.semiBold,
 26→};
 27→
 28→const BASE_FONT_SIZES: Record<string, number> = {
 29→  bold: 34,
 30→  handwritten: 32,
 31→};
 32→const DEFAULT_BASE_SIZE = 30;
 33→const MIN_FONT = 6;
 34→const MAX_FONT = 48;
 35→
 36→function clamp(value: number, min: number, max: number) {
 37→  return Math.min(max, Math.max(min, value));
 38→}
 39→
 40→export function CanvasPreview({canvasDoc, width}: CanvasPreviewProps) {
 41→  const doc = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);
 42→
 43→  const hasContent =
 44→    (doc?.snippets?.length ?? 0) > 0 ||
 45→    (doc?.images?.length ?? 0) > 0 ||
 46→    (doc?.doodles?.length ?? 0) > 0;
 47→
 48→  if (!doc || !hasContent) return null;
 49→
 50→  const ratio = ASPECT_RATIOS[doc.meta?.aspectRatio ?? ''] ?? 4 / 5;
 51→  const height = Math.min(180, width / ratio);
 52→  const scale = width / STAGE_WIDTH;
 53→  const bgColor = doc.meta?.theme === 'dark' ? '#1A1A1A' : '#FAFAFA';
 54→  const defaultTextColor = doc.meta?.theme === 'dark' ? '#FAFAFA' : '#1A1A1A';
 55→
 56→  const sortedImages = [...(doc.images ?? [])].sort(
 57→    (a, b) => (a.zIndex ?? 0) - (b.zIndex ?? 0),
 58→  );
 59→  const sortedSnippets = [...(doc.snippets ?? [])].sort(
 60→    (a, b) => (a.zIndex ?? 0) - (b.zIndex ?? 0),
 61→  );
 62→
 63→  return (
 64→    <View style={[styles.container, {width, height, backgroundColor: bgColor}]}>
 65→      {/* Images layer */}
 66→      {sortedImages.map((img: CanvasImage) => (
 67→        <Image
 68→          key={img.id}
 69→          source={{uri: img.src}}
 70→          style={{
 71→            position: 'absolute',
 72→            left: img.x * width,
 73→            top: img.y * height,
 74→            width: img.width * width,
 75→            height: img.height * height,
 76→            transform: [
 77→              ...(img.rotation ? [{rotate: `${img.rotation}deg`}] : []),
 78→              ...(img.scaleX != null && img.scaleX < 0 ? [{scaleX: -1}] : []),
 79→            ],
 80→          }}
 81→          resizeMode="cover"
 82→        />
 83→      ))}
 84→
 85→      {/* Text snippets layer */}
 86→      {sortedSnippets.map((snippet: CanvasSnippet) => {
 87→        const baseSize = BASE_FONT_SIZES[snippet.fontStyle ?? ''] ?? DEFAULT_BASE_SIZE;
 88→        const sizeScale = snippet.sizeScale ?? 1;
 89→        const fontSize = clamp(baseSize * sizeScale * scale, MIN_FONT, MAX_FONT);
 90→        const fontFamily = FONT_MAP[snippet.fontStyle ?? ''] ?? fonts.ui.regular;
 91→
 92→        return (
 93→          <Text
 94→            key={snippet.id}
 95→            numberOfLines={3}
 96→            style={{
 97→              position: 'absolute',
 98→              left: snippet.x * width,
 99→              top: snippet.y * height,
100→              fontSize,
101→              fontFamily,
102→              color: defaultTextColor,
103→              transform: [
104→                ...(snippet.rotation ? [{rotate: `${snippet.rotation}deg`}] : []),
105→                ...(snippet.scaleX != null && snippet.scaleX < 0 ? [{scaleX: -1}] : []),
106→              ],
107→            }}>
108→            {snippet.text}
109→          </Text>
110→        );
111→      })}
112→
113→      {/* Doodles layer */}
114→      {doc.doodles && doc.doodles.length > 0 ? (
115→        <Svg
116→          width={width}
117→          height={height}
118→          style={StyleSheet.absoluteFill}
119→          pointerEvents="none">
120→          {doc.doodles.map((doodle: CanvasDoodle) => {
121→            const pts = doodle.points;
122→            if (!pts || pts.length < 4) return null;
123→            const pointStr = [];
124→            for (let i = 0; i < pts.length; i += 2) {
125→              pointStr.push(`${pts[i] * width},${pts[i + 1] * height}`);
126→            }
127→            return (
128→              <Polyline
129→                key={doodle.id}
130→                points={pointStr.join(' ')}
131→                fill="none"
132→                stroke={doodle.color ?? defaultTextColor}
133→                strokeWidth={Math.max(1, (doodle.size ?? 2) * scale)}
134→                strokeLinecap="round"
135→                strokeLinejoin="round"
136→              />
137→            );
138→          })}
139→        </Svg>
140→      ) : null}
141→    </View>
142→  );
143→}
144→
145→const styles = StyleSheet.create({
146→  container: {
147→    overflow: 'hidden',
148→  },
149→});
