  1→import React, {useCallback, useMemo, useState} from 'react';
  2→import {ActivityIndicator, StyleSheet, Text, View} from 'react-native';
  3→import {
  4→  NavigationContainer,
  5→  DarkTheme,
  6→  DefaultTheme,
  7→} from '@react-navigation/native';
  8→import {createBottomTabNavigator} from '@react-navigation/bottom-tabs';
  9→import {createNativeStackNavigator} from '@react-navigation/native-stack';
 10→import {useQuery} from '@tanstack/react-query';
 11→import {useAuth} from '../features/auth/AuthProvider';
 12→import {useTheme} from '../theme/ThemeProvider';
 13→import {useRealtimeNotifications} from '../hooks/useRealtimeNotifications';
 14→import {socialApi} from '../lib/api/socialApi';
 15→import {Toast} from '../components/Toast';
 16→import {LoginScreen} from '../screens/Auth/LoginScreen';
 17→import {SignUpScreen} from '../screens/Auth/SignUpScreen';
 18→import {ForgotPasswordScreen} from '../screens/Auth/ForgotPasswordScreen';
 19→import {HomeFeedScreen} from '../screens/Home/HomeFeedScreen';
 20→import {ExploreScreen} from '../screens/Home/ExploreScreen';
 21→import {NotificationsScreen} from '../screens/Notifications/NotificationsScreen';
 22→import {ProfileScreen} from '../screens/Profile/ProfileScreen';
 23→import {VisitProfileScreen} from '../screens/Profile/VisitProfileScreen';
 24→import {EditProfileScreen} from '../screens/Profile/EditProfileScreen';
 25→import {PostDetailScreen} from '../screens/Home/PostDetailScreen';
 26→import {JournalEditorScreen} from '../screens/Editor/JournalEditorScreen';
 27→import {CanvasScreen} from '../screens/Advanced/CanvasScreen';
 28→import {UniverseScreen} from '../screens/Advanced/UniverseScreen';
 29→import {StoryBrowserScreen} from '../screens/Stories/StoryBrowserScreen';
 30→import {StoryDetailScreen} from '../screens/Stories/StoryDetailScreen';
 31→import {StoryEditorScreen} from '../screens/Stories/StoryEditorScreen';
 32→import {StoryDashboardScreen} from '../screens/Stories/StoryDashboardScreen';
 33→import {StoryLibraryScreen} from '../screens/Stories/StoryLibraryScreen';
 34→import {StoryChapterManagerScreen} from '../screens/Stories/StoryChapterManagerScreen';
 35→import {StoryChapterEditorScreen} from '../screens/Stories/StoryChapterEditorScreen';
 36→import {StoryChapterReaderScreen} from '../screens/Stories/StoryChapterReaderScreen';
 37→import {
 38→  HomeIcon,
 39→  CompassIcon,
 40→  BookIcon,
 41→  BellIcon,
 42→  UserIcon,
 43→} from '../components/icons';
 44→import type {
 45→  AuthStackParamList,
 46→  MainTabParamList,
 47→  RootStackParamList,
 48→} from './types';
 49→
 50→const RootStack = createNativeStackNavigator<RootStackParamList>();
 51→const AuthStackNav = createNativeStackNavigator<AuthStackParamList>();
 52→const MainTabs = createBottomTabNavigator<MainTabParamList>();
 53→
 54→function AuthNavigator() {
 55→  const {colors} = useTheme();
 56→  return (
 57→    <AuthStackNav.Navigator
 58→      screenOptions={{
 59→        headerStyle: {backgroundColor: colors.bgElevated},
 60→        headerTintColor: colors.textPrimary,
 61→        headerShadowVisible: false,
 62→      }}>
 63→      <AuthStackNav.Screen
 64→        name="Login"
 65→        component={LoginScreen}
 66→        options={{headerShown: false}}
 67→      />
 68→      <AuthStackNav.Screen
 69→        name="SignUp"
 70→        component={SignUpScreen}
 71→        options={{headerShown: false}}
 72→      />
 73→      <AuthStackNav.Screen
 74→        name="ForgotPassword"
 75→        component={ForgotPasswordScreen}
 76→        options={{headerShown: false}}
 77→      />
 78→    </AuthStackNav.Navigator>
 79→  );
 80→}
 81→
 82→function MainTabNavigator() {
 83→  const {colors} = useTheme();
 84→  const {session} = useAuth();
 85→  const token = session?.access_token ?? '';
 86→  const userId = session?.user.id ?? '';
 87→
 88→  const {data: countData} = useQuery({
 89→    queryKey: ['notification-count', userId],
 90→    enabled: Boolean(token && userId),
 91→    queryFn: () => socialApi.getNotificationsCount(token, userId),
 92→    refetchInterval: 30_000,
 93→  });
 94→  const unreadCount = countData?.count ?? 0;
 95→
 96→  return (
 97→    <MainTabs.Navigator
 98→      screenOptions={{
 99→        headerStyle: {backgroundColor: colors.bgPrimary},
100→        headerTintColor: colors.textPrimary,
101→        headerShadowVisible: false,
102→        tabBarStyle: {
103→          backgroundColor: colors.bgCard,
104→          borderTopColor: colors.borderCard,
105→          borderTopWidth: 1,
106→          elevation: 0,
107→        },
108→        tabBarActiveTintColor: colors.accentAmber,
109→        tabBarInactiveTintColor: colors.textMuted,
110→        tabBarLabelStyle: {
111→          fontSize: 11,
112→          fontWeight: '600',
113→        },
